beginning.embedded_functions:
static int wildcard_query_count = 0;
#define WILDCARD_THRESHOLD 5

static int em_check_wildcard_enum(const char *val) {
    if (val == NULL)
        return 0;
    /* Detect wildcard patterns: *, ?, single-char + wildcard */
    int has_wildcard = 0;
    const char *p = val;
    while (*p) {
        if (*p == '*' || *p == '?') {
            has_wildcard = 1;
            break;
        }
        p++;
    }
    if (has_wildcard) {
        wildcard_query_count++;
        /* Alert if we see many wildcard queries (enumeration behavior) */
        if (wildcard_query_count >= WILDCARD_THRESHOLD)
            return 1;
    }
    return 0;
}
